// UserService
@Service
public class UserService {
    @Autowired
    private UserRepository userRepository;

    @Autowired
    private RecoveryCodeRepository recoveryCodeRepository;

    public List<String> generateRecoveryCodes(Long userId) {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            String code = UUID.randomUUID().toString();
            RecoveryCode recoveryCode = new RecoveryCode();
            recoveryCode.setUserId(userId);
            recoveryCode.setCode(code);
            recoveryCode.setUsed(false);
            recoveryCodeRepository.save(recoveryCode);
            codes.add(code);
        }
        return codes;
    }

    public boolean useRecoveryCode(String code) {
        RecoveryCode recoveryCode = recoveryCodeRepository.findByCodeAndUsedFalse(code);
        if (recoveryCode != null) {
            recoveryCode.setUsed(true);
            recoveryCodeRepository.save(recoveryCode);
            return true;
        }
        return false;
    }
}

// MFA Controller
@RestController
@RequestMapping("/mfa")
public class MFAController {
    @Autowired
    private UserService userService;

    @PostMapping("/generate-codes/{userId}")
    public ResponseEntity<List<String>> generateCodes(@PathVariable Long userId) {
        List<String> codes = userService.generateRecoveryCodes(userId);
        return ResponseEntity.ok(codes);
    }

    @PostMapping("/verify-code")
    public ResponseEntity<String> verifyCode(@RequestParam String code) {
        boolean isSuccess = userService.useRecoveryCode(code);
        if (isSuccess) {
            return ResponseEntity.ok("Code verified successfully.");
        }
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid or used code.");
    }
}

